import{_ as p,o as t,c as r,ag as o}from"./chunks/framework.BZohXCq9.js";const d=JSON.parse('{"title":"第5集：两盘棋","description":"","frontmatter":{"title":"第5集：两盘棋","outline":false},"headers":[],"relativePath":"novels/jin-gu-yao/drama/05.md","filePath":"novels/jin-gu-yao/drama/05.md","lastUpdated":1774160915000}'),n={name:"novels/jin-gu-yao/drama/05.md"};function a(s,e,m,g,l,i){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="第-5-集-两盘棋" tabindex="-1">第 5 集：两盘棋 <a class="header-anchor" href="#第-5-集-两盘棋" aria-label="Permalink to &quot;第 5 集：两盘棋&quot;">​</a></h1><blockquote><p>钩子类型：双线交汇 + 大悬念 时长：约 4 分钟</p></blockquote><hr><h2 id="【a线-三娘在路上】" tabindex="-1">【A线：三娘在路上】 <a class="header-anchor" href="#【a线-三娘在路上】" aria-label="Permalink to &quot;【A线：三娘在路上】&quot;">​</a></h2><p><em>画面：官道。三娘一行人在走。</em></p><p><em>柴令武终于醒了，骑在马三宝肩上，兴高采烈。</em></p><p><strong>柴令武</strong>：三宝！跑！</p><p><strong>马三宝</strong>（气喘）：小公子……我不是马……</p><p><strong>柴令武</strong>：驾！</p><p><em>柴哲威在旁边走着，时不时回头张望，一副小大人的样子。</em></p><p><em>三娘走在前面，表情平静，但眼睛一直在观察——路上的行人、远处的烟尘、道旁的地形。</em></p><p><strong>三娘（画外音）</strong>：从长安到鄠县，正常走两天。我们带着孩子，得三天。这三天是最危险的——还没到庄园，在路上就是活靶子。</p><p><em>她的目光落在远处一个茶棚上。茶棚前拴着几匹马。</em></p><p><em>三娘停下脚步。</em></p><p><strong>马三宝</strong>：怎么了？</p><p><strong>三娘</strong>（低声）：那几匹马。看蹄铁。</p><p><em>马三宝看了一眼。</em></p><p><strong>马三宝</strong>：……官马。</p><p><strong>三娘</strong>：嗯。官差在里面歇脚。绕路。</p><p><em>一行人拐进旁边的小路。</em></p><hr><h2 id="【b线-鄠县县衙】" tabindex="-1">【B线：鄠县县衙】 <a class="header-anchor" href="#【b线-鄠县县衙】" aria-label="Permalink to &quot;【B线：鄠县县衙】&quot;">​</a></h2><p><em>中年人坐在案后。一个手下进来。</em></p><p><strong>手下</strong>：大人，柴绍已经失踪了。长安那边确认——是夜里走的。</p><p><strong>中年人</strong>：往哪个方向？</p><p><strong>手下</strong>：北。太原方向。</p><p><em>中年人点点头，不意外。</em></p><p><strong>中年人</strong>：柴府呢？还有谁？</p><p><strong>手下</strong>：柴绍的妻子，李渊第三女。两个小孩。还有一些仆从。</p><p><em>中年人端起茶碗，吹了吹。</em></p><p><strong>中年人</strong>：一个女人，两个小孩。</p><p><em>他喝了一口茶。</em></p><p><strong>中年人</strong>：盯着。</p><hr><h2 id="【a线-夜晚露宿】" tabindex="-1">【A线：夜晚露宿】 <a class="header-anchor" href="#【a线-夜晚露宿】" aria-label="Permalink to &quot;【A线：夜晚露宿】&quot;">​</a></h2><p><em>路边，简单的营地。仆从们在轮流守夜。</em></p><p><em>柴哲威和柴令武睡了。</em></p><p><em>三娘坐在树下，没有睡。</em></p><p><em>马三宝凑过来。</em></p><p><strong>马三宝</strong>（低声）：公子，到了鄠县之后……然后呢？</p><p><em>三娘看着远处。月亮又大又亮，和长安柴府窗前看到的是同一个。</em></p><p><strong>三娘</strong>：开仓。</p><p><strong>马三宝</strong>：啊？</p><p><strong>三娘</strong>：李氏庄园的粮仓，存了八年的粮。周围十几个村落，这两年收成不好。有粮，就有人。有人，就有兵。</p><p><em>马三宝张着嘴。</em></p><p><strong>马三宝</strong>：夫——公子，您是什么时候想好的这些？</p><p><em>三娘微微一笑。</em></p><p><strong>三娘</strong>：八年前。</p><p><em>马三宝想起了那次鄠县之行。他终于明白了。</em></p><hr><h2 id="【b线-同一个夜晚】" tabindex="-1">【B线：同一个夜晚】 <a class="header-anchor" href="#【b线-同一个夜晚】" aria-label="Permalink to &quot;【B线：同一个夜晚】&quot;">​</a></h2><p><em>鄠县县衙。</em></p><p><em>中年人也没有睡。他在灯下摊开地图，上面已经密密麻麻标满了记号——李氏庄园的位置、周边村落、山头、水源、道路。</em></p><p><em>他的标记方式——和三娘让马三宝做的调查，重合度极高。</em></p><p><em>一个手下进来。</em></p><p><strong>手下</strong>：大人，李氏庄园那边有动静。管事的好像在清点什么。</p><p><em>中年人放下笔。</em></p><p><strong>中年人</strong>：清点粮仓？</p><p><strong>手下</strong>：像是。</p><p><em>中年人的眼睛亮了。</em></p><p><strong>中年人</strong>：有意思。</p><p><em>他站起来，走到窗前。月亮很亮。</em></p><p><strong>中年人</strong>（自言自语）：李渊，你是让女儿来打前站的？……还是你女儿自己要来的？</p><hr><h2 id="【第-5-集钩子-·-第一季终】" tabindex="-1">【第 5 集钩子 · 第一季终】 <a class="header-anchor" href="#【第-5-集钩子-·-第一季终】" aria-label="Permalink to &quot;【第 5 集钩子 · 第一季终】&quot;">​</a></h2><p><em>画面分屏——</em></p><p><em>左边：三娘在月光下，目光坚定，望向鄠县方向。</em></p><p><em>右边：中年人在灯下，嘴角微扬，望向同一个方向。</em></p><p><em>两个人，两盘棋，即将在同一个棋盘上相遇。</em></p><p><em>字幕渐出：</em></p><p><strong>&quot;她以为鄠县是起点。他以为鄠县是陷阱。&quot;</strong></p><p><strong>&quot;他们都对了。&quot;</strong></p><p><em>黑屏。</em></p><p><strong>第一季完 · 第二季《开仓》即将开始</strong></p><hr><p><em>第 5 集 完</em></p>',76)])])}const c=p(n,[["render",a]]);export{d as __pageData,c as default};
